/**
 * Subscription Module Public API
 *
 * Centralized exports for the Subscription module.
 * Import from this file when using subscription module functionality
 * from other parts of the application.
 *
 * @module modules/_core/subscription
 *
 * @example
 * ```typescript
 * import {
 *   SubscriptionModule,
 *   SubscriptionService,
 *   subscriptionRoutes,
 *   type Plan,
 *   type Subscription,
 *   type FeatureCheckResult,
 * } from '@/modules/_core/subscription';
 * ```
 */

// -----------------------------------------------------------------------------
// Module Definition
// -----------------------------------------------------------------------------

export { SubscriptionModule, default } from '@/modules/_core/subscription/subscription.module';
export type {
  SubscriptionModuleContext,
  SubscriptionModuleHooks,
} from '@/modules/_core/subscription/subscription.module';

// -----------------------------------------------------------------------------
// Service
// -----------------------------------------------------------------------------

export { SubscriptionService } from '@/modules/_core/subscription/subscription.service';

// -----------------------------------------------------------------------------
// Repository
// -----------------------------------------------------------------------------

export { SubscriptionRepository } from '@/modules/_core/subscription/subscription.repository';
export type {
  PaginatedResult,
  CreateSubscriptionData,
  UpdateSubscriptionData,
  CreateInvoiceData,
} from '@/modules/_core/subscription/subscription.repository';

// -----------------------------------------------------------------------------
// Controller
// -----------------------------------------------------------------------------

export { SubscriptionController } from '@/modules/_core/subscription/subscription.controller';

// -----------------------------------------------------------------------------
// Routes
// -----------------------------------------------------------------------------

export {
  subscriptionRoutes,
  buildSubscriptionApiPath,
  buildSubscriptionAdminPath,
  isPublicSubscriptionRoute,
  isProtectedSubscriptionRoute,
  subscriptionEndpoints,
} from '@/modules/_core/subscription/subscription.routes';
export type {
  SubscriptionRouteConfig,
  SubscriptionEndpointMetadata,
} from '@/modules/_core/subscription/subscription.routes';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

// Plan types
export type {
  Plan,
  PlanTier,
  PlanFeatures,
  CoreFeatures,
  OrderFeatures,
  AIFeatures,
  AdvancedFeatures,
  PlanLimits,
  ResourceLimits,
  MonthlyLimits,
  PlanSummary,
} from '@/modules/_core/subscription/subscription.types';

// Subscription types
export type {
  Subscription,
  SubscriptionWithRelations,
  SubscriptionMetadata,
  PlanChangeRecord,
  SubscriptionSummary,
} from '@/modules/_core/subscription/subscription.types';

// Invoice types
export type {
  Invoice,
  InvoiceLineItem,
  InvoiceMetadata,
  BillingAddress,
} from '@/modules/_core/subscription/subscription.types';

// Feature gating types
export type {
  FeatureCheckResult,
  LimitCheckResult,
  UsageSummary,
  UsageItem,
} from '@/modules/_core/subscription/subscription.types';

// Request/Response types
export type {
  CreateSubscriptionRequest,
  CreateSubscriptionResponse,
  UpdateSubscriptionRequest,
  UpdateSubscriptionResponse,
  ChangePlanRequest,
  ChangePlanResponse,
  CancelSubscriptionRequest,
  CancelSubscriptionResponse,
  ReactivateSubscriptionRequest,
  ReactivateSubscriptionResponse,
} from '@/modules/_core/subscription/subscription.types';

// Query/Filter types
export type {
  SubscriptionListFilters,
  SubscriptionListParams,
  InvoiceListFilters,
  InvoiceListParams,
} from '@/modules/_core/subscription/subscription.types';

// Event types
export type {
  SubscriptionCreatedEvent,
  SubscriptionCancelledEvent,
  PlanChangedEvent,
  TrialStartedEvent,
  TrialEndedEvent,
  InvoicePaidEvent,
} from '@/modules/_core/subscription/subscription.types';

// Hook context types
export type {
  BeforeCreateContext,
  AfterCreateContext,
  BeforePlanChangeContext,
  AfterPlanChangeContext,
} from '@/modules/_core/subscription/subscription.types';

// Module settings types
export type { SubscriptionModuleSettings } from '@/modules/_core/subscription/subscription.types';

// Type guards
export {
  isPlan,
  isSubscription,
  isPlanTier,
  getTierOrder,
  isTierHigher,
} from '@/modules/_core/subscription/subscription.types';

// -----------------------------------------------------------------------------
// Schemas (Zod validation)
// -----------------------------------------------------------------------------

export {
  // Base schemas
  planNameSchema,
  displayNameSchema,
  priceSchema,
  currencySchema,
  cuidSchema,

  // Plan schemas
  planFeaturesSchema,
  planLimitsSchema,
  createPlanSchema,
  updatePlanSchema,

  // Subscription schemas
  subscriptionMetadataSchema,
  createSubscriptionSchema,
  updateSubscriptionSchema,
  changePlanSchema,
  cancelSubscriptionSchema,
  reactivateSubscriptionSchema,

  // Query schemas
  subscriptionListQuerySchema,
  planListQuerySchema,
  invoiceListQuerySchema,
  subscriptionIdSchema,
  featureCheckSchema,
  limitCheckSchema,

  // Response schemas
  planResponseSchema,
  subscriptionResponseSchema,

  // Module settings schema
  subscriptionModuleSettingsSchema,

  // Utility functions
  calculateProration,
  daysUntilExpiry,
  generateInvoiceNumber,
  compareTiers,
} from '@/modules/_core/subscription/subscription.schema';

export type {
  CreatePlanInput,
  UpdatePlanInput,
  CreateSubscriptionInput,
  UpdateSubscriptionInput,
  ChangePlanInput,
  CancelSubscriptionInput,
  ReactivateSubscriptionInput,
  SubscriptionListQueryInput,
  PlanListQueryInput,
  InvoiceListQueryInput,
  SubscriptionIdInput,
  FeatureCheckInput,
  LimitCheckInput,
  SubscriptionModuleSettingsInput,
} from '@/modules/_core/subscription/subscription.schema';
